def process_graph(graph_data):
    # Create a copy of the input graph to avoid mutating the original
    graph_copy = graph_data.copy()

    # Locate the parent node with name 'ju1.s1.dom'
    parent_id = None
    for nid, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.s1.dom':
            parent_id = nid
            break

    # Add the new EK_PACKET_SWITCH node under the identified parent
    if parent_id is not None:
        new_node_id = 'new_EK_PACKET_SWITCH_16'
        if new_node_id not in graph_copy:
            graph_copy.add_node(
                new_node_id,
                name='new_EK_PACKET_SWITCH_16',
                type=['EK_PACKET_SWITCH']
            )
            graph_copy.add_edge(parent_id, new_node_id, type='RK_CONTAINS')

    # Helper to compute total physical capacity for a given node
    def _total_capacity(start_node):
        total = 0
        stack = [start_node]
        visited = set()
        while stack:
            cur = stack.pop()
            if cur in visited:
                continue
            visited.add(cur)
            cur_attrs = graph_copy.nodes[cur]
            # If this node is a PORT, add its capacity
            if 'EK_PORT' in cur_attrs.get('type', []):
                cap = cur_attrs.get('physical_capacity_bps', 0)
                if isinstance(cap, (int, float)):
                    total += cap
            # Traverse to children via RK_CONTAINS edges
            for _, child, edata in graph_copy.out_edges(cur, data=True):
                if edata.get('type') == 'RK_CONTAINS':
                    stack.append(child)
        return total

    # Gather direct children of the parent and compute their capacities
    child_capacities = []
    if parent_id is not None:
        for _, child, edata in graph_copy.out_edges(parent_id, data=True):
            if edata.get('type') == 'RK_CONTAINS':
                child_name = graph_copy.nodes[child].get('name')
                capacity = _total_capacity(child)
                child_capacities.append([child_name, capacity])

    # Rank children by total capacity (descending)
    child_capacities.sort(key=lambda x: x[1], reverse=True)

    # Serialize the updated graph to JSON format
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)

    # Return the result in the required structure
    return {
        'type': 'list',
        'data': child_capacities,
        'updated_graph': graph_json
    }

